import { Request, Response, NextFunction } from 'express';
import { messageService } from '../services/message.service';

export const getMessages = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { roomId } = req.params;
    const { since } = req.query;
    const messages = await messageService.getMessagesSince(roomId, since as string);
    res.json({ messages, serverTime: new Date().toISOString() });
  } catch (err) { next(err); }
};

export const postMessage = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { roomId } = req.params;
    const { text } = req.body;
    const userId = req.user!.id;
    const message = await messageService.createMessage({ roomId, userId, text });
    res.status(201).json({ message });
  } catch (err) { next(err); }
};

import { MessageModel } from '../models/message.model';

export const messageService = {
  async getMessagesSince(roomId: string, since?: string) {
    const filter: Record<string, unknown> = { roomId };
    if (since) filter.createdAt = { $gt: new Date(since) };
    return MessageModel.find(filter).sort({ createdAt: 1 }).lean();
  },
  async createMessage(input: { roomId: string; userId: string; text: string }) {
    return MessageModel.create(input);
  }
};

import { useEffect, useState } from 'react';
import { fetchMessagesSince } from '../../api/messages';

type Message = { _id: string; userId: string; text: string; createdAt: string };

export function ChatRoom({ roomId }: { roomId: string }) {
  const [messages, setMessages] = useState<Message[]>([]);
  const [lastTime, setLastTime] = useState<string | null>(null);
  useEffect(() => {
    const id = setInterval(async () => {
      const res = await fetchMessagesSince(roomId, lastTime ?? undefined);
      if (res.messages.length) {
        setMessages(prev => [...prev, ...res.messages]);
        setLastTime(res.serverTime);
      }
    }, 3000);
    return () => clearInterval(id);
  }, [roomId, lastTime]);
  return <ul>{messages.map(m => <li key={m._id}>{m.text}</li>)}</ul>;
}

import { EventEmitter } from 'node:events';
import type { MessageDoc } from '../models/message.model';

type Events = {
  'message.created': (msg: MessageDoc) => void;
  'presence.changed': (payload: { roomId: string; userId: string; online: boolean }) => void;
};

class TypedBus extends EventEmitter {
  override on<K extends keyof Events>(event: K, listener: Events[K]): this { return super.on(event, listener); }
  override emit<K extends keyof Events>(event: K, ...args: Parameters<Events[K]>): boolean { return super.emit(event, ...args); }
}

export const messageBus = new TypedBus();

import { MessageModel, type MessageDoc } from '../models/message.model';
import { messageBus } from '../events/message.bus';

export const messageService = {
  async getMessagesSince(roomId: string, since?: string): Promise<MessageDoc[]> {
    const filter: Record<string, unknown> = { roomId };
    if (since) filter.createdAt = { $gt: new Date(since) };
    return MessageModel.find(filter).sort({ createdAt: 1 }).lean();
  },
  async createMessage(input: { roomId: string; userId: string; text: string }): Promise<MessageDoc> {
    const msg = await MessageModel.create(input);
    messageBus.emit('message.created', msg);
    return msg;
  }
};

import { Server, Socket } from 'socket.io';
import { createAdapter } from '@socket.io/redis-adapter';
import { createClient } from 'redis';
import { verifyJwt } from '../auth/jwt';
import { messageBus } from '../events/message.bus';
import { presenceRepo } from '../dal/presence.repo';

interface AuthedSocket extends Socket { data: { userId: string } }

export async function attachChatNamespace(io: Server) {
  const pub = createClient({ url: process.env.REDIS_URL });
  const sub = pub.duplicate();
  await Promise.all([pub.connect(), sub.connect()]);
  io.adapter(createAdapter(pub, sub));

  const ns = io.of('/chat');
  ns.use(async (socket, next) => {
    try {
      const token = socket.handshake.auth.token as string | undefined;
      if (!token) return next(new Error('UNAUTHENTICATED'));
      const { sub } = await verifyJwt(token);
      (socket as AuthedSocket).data.userId = sub;
      next();
    } catch { next(new Error('UNAUTHENTICATED')); }
  });

  ns.on('connection', (socket: AuthedSocket) => {
    socket.on('room:join', async (roomId: string) => {
      await socket.join(`room:${roomId}`);
      await presenceRepo.markOnline(roomId, socket.data.userId);
      ns.to(`room:${roomId}`).emit('presence:changed', { userId: socket.data.userId, online: true });
    });
    socket.on('room:leave', async (roomId: string) => {
      await socket.leave(`room:${roomId}`);
      await presenceRepo.markOffline(roomId, socket.data.userId);
      ns.to(`room:${roomId}`).emit('presence:changed', { userId: socket.data.userId, online: false });
    });
    socket.on('disconnect', async () => {
      const rooms = await presenceRepo.roomsForUser(socket.data.userId);
      for (const roomId of rooms) {
        await presenceRepo.markOffline(roomId, socket.data.userId);
        ns.to(`room:${roomId}`).emit('presence:changed', { userId: socket.data.userId, online: false });
      }
    });
  });

  messageBus.on('message.created', (msg) => {
    ns.to(`room:${msg.roomId}`).emit('message:new', msg);
  });
}

import { useEffect, useRef, useState } from 'react';
import { io, Socket } from 'socket.io-client';

type Message = { _id: string; userId: string; text: string; createdAt: string };

export function useChatSocket(roomId: string, token: string) {
  const [messages, setMessages] = useState<Message[]>([]);
  const [presence, setPresence] = useState<Set<string>>(new Set());
  const [connected, setConnected] = useState(false);
  const socketRef = useRef<Socket | null>(null);

  useEffect(() => {
    const socket = io('/chat', { auth: { token }, transports: ['websocket'] });
    socketRef.current = socket;
    socket.on('connect', () => { setConnected(true); socket.emit('room:join', roomId); });
    socket.on('disconnect', () => setConnected(false));
    socket.on('message:new', (m: Message) => setMessages(prev => [...prev, m]));
    socket.on('presence:changed', ({ userId, online }: { userId: string; online: boolean }) => {
      setPresence(prev => { const next = new Set(prev); if (online) next.add(userId); else next.delete(userId); return next; });
    });
    return () => {
      socket.emit('room:leave', roomId);
      socket.removeAllListeners();
      socket.disconnect();
    };
  }, [roomId, token]);

  return { messages, presence, connected };
}

import { Schema, model, Types } from 'mongoose';

const LineItemSchema = new Schema({ productId: { type: Types.ObjectId, required: true }, quantity: { type: Number, required: true }, unitPrice: { type: Number, required: true } }, { _id: false });

const OrderSchema = new Schema({
  customerId: { type: Types.ObjectId, required: true, index: true },
  status: { type: String, enum: ['pending','paid','shipped','delivered','cancelled','refunded'], default: 'pending' },
  lineItems: [LineItemSchema],
  total: { type: Number, required: true },
  paidAt: Date,
  shippedAt: Date,
  refundedAmount: { type: Number, default: 0 }
}, { timestamps: true });

export const OrderModel = model('Order', OrderSchema);

import { Request, Response, NextFunction } from 'express';
import { OrderModel } from '../models/order.model';

export const refundOrder = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { orderId } = req.params;
    const { amount } = req.body;
    const order = await OrderModel.findById(orderId);
    if (!order) return res.status(404).json({ error: 'NOT_FOUND' });
    if (order.status !== 'paid' && order.status !== 'shipped' && order.status !== 'delivered') return res.status(400).json({ error: 'INVALID_STATE' });
    if (order.refundedAmount + amount > order.total) return res.status(400).json({ error: 'REFUND_EXCEEDS_TOTAL' });
    order.refundedAmount += amount;
    if (order.refundedAmount === order.total) order.status = 'refunded';
    await order.save();
    res.json({ order });
  } catch (err) { next(err); }
};

import type { ObjectId } from 'mongoose';

export type OrderStatus = 'pending'|'paid'|'shipped'|'delivered'|'cancelled'|'refunded';
export type LineItem = { productId: ObjectId; quantity: number; unitPrice: number };
export type DomainEvent = { type: 'OrderRefunded'; orderId: ObjectId; amount: number; fullyRefunded: boolean };

export class OrderAggregate {
  private events: DomainEvent[] = [];
  private constructor(
    public readonly id: ObjectId,
    public readonly customerId: ObjectId,
    private _status: OrderStatus,
    private readonly lineItems: ReadonlyArray<LineItem>,
    private readonly total: number,
    private _refundedAmount: number,
    private _paidAt: Date | null,
    private _shippedAt: Date | null
  ) {}

  static rehydrate(snap: { id: ObjectId; customerId: ObjectId; status: OrderStatus; lineItems: LineItem[]; total: number; refundedAmount: number; paidAt: Date | null; shippedAt: Date | null }): OrderAggregate {
    const computed = snap.lineItems.reduce((s, i) => s + i.unitPrice * i.quantity, 0);
    if (Math.abs(computed - snap.total) > 0.01) throw new Error('INVARIANT_TOTAL_MISMATCH');
    return new OrderAggregate(snap.id, snap.customerId, snap.status, snap.lineItems, snap.total, snap.refundedAmount, snap.paidAt, snap.shippedAt);
  }

  get status(): OrderStatus { return this._status; }
  get refundedAmount(): number { return this._refundedAmount; }
  pullEvents(): DomainEvent[] { const e = this.events; this.events = []; return e; }

  refund(amount: number): void {
    if (amount <= 0) throw new Error('REFUND_AMOUNT_INVALID');
    if (!['paid','shipped','delivered','refunded'].includes(this._status)) throw new Error('INVALID_STATE_FOR_REFUND');
    if (this._refundedAmount + amount > this.total) throw new Error('REFUND_EXCEEDS_TOTAL');
    this._refundedAmount += amount;
    const fully = Math.abs(this._refundedAmount - this.total) < 0.01;
    if (fully) this._status = 'refunded';
    this.events.push({ type: 'OrderRefunded', orderId: this.id, amount, fullyRefunded: fully });
  }

  toSnapshot() { return { id: this.id, customerId: this.customerId, status: this._status, lineItems: [...this.lineItems], total: this.total, refundedAmount: this._refundedAmount, paidAt: this._paidAt, shippedAt: this._shippedAt }; }
}

import { OrderModel } from '../models/order.model';
import { OrderAggregate } from '../domain/order/order.aggregate';
import type { ObjectId } from 'mongoose';
import { domainEventBus } from '../events/domain.bus';

export const orderRepository = {
  async findById(id: ObjectId): Promise<OrderAggregate | null> {
    const doc = await OrderModel.findById(id).lean();
    if (!doc) return null;
    return OrderAggregate.rehydrate({ id: doc._id, customerId: doc.customerId, status: doc.status, lineItems: doc.lineItems, total: doc.total, refundedAmount: doc.refundedAmount, paidAt: doc.paidAt ?? null, shippedAt: doc.shippedAt ?? null });
  },
  async save(agg: OrderAggregate): Promise<void> {
    const snap = agg.toSnapshot();
    const result = await OrderModel.updateOne({ _id: snap.id }, { $set: { status: snap.status, refundedAmount: snap.refundedAmount, paidAt: snap.paidAt, shippedAt: snap.shippedAt } });
    if (result.matchedCount === 0) throw new Error('CONCURRENT_DELETION');
    for (const evt of agg.pullEvents()) domainEventBus.emit(evt.type, evt);
  }
};

import { Request, Response, NextFunction } from 'express';
import { Types } from 'mongoose';
import { orderRepository } from '../dal/order.repository';
import { HttpError } from '../errors/http-error';

export const refundOrder = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const orderId = new Types.ObjectId(req.params.orderId);
    const { amount } = req.body as { amount: number };
    const order = await orderRepository.findById(orderId);
    if (!order) throw new HttpError(404, 'NOT_FOUND');
    order.refund(amount);
    await orderRepository.save(order);
    res.json({ order: order.toSnapshot() });
  } catch (err) {
    if (err instanceof Error && ['INVALID_STATE_FOR_REFUND','REFUND_EXCEEDS_TOTAL','REFUND_AMOUNT_INVALID'].includes(err.message)) return next(new HttpError(400, err.message));
    next(err);
  }
};

import { Request, Response, NextFunction } from 'express';
import { UserModel } from '../models/user.model';
import { OrderModel } from '../models/order.model';
import { PaymentModel } from '../models/payment.model';
import { RefundModel } from '../models/refund.model';
import { SessionModel } from '../models/session.model';
import { SupportTicketModel } from '../models/support-ticket.model';
import { AuditLogModel } from '../models/audit-log.model';

export const getOverview = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const since = new Date(Date.now() - 24*60*60*1000);
    const [users, orders, payments, refunds, sessions, tickets, audits] = await Promise.all([
      UserModel.aggregate([{ $match: { createdAt: { $gte: since } } }, { $count: 'n' }]),
      OrderModel.aggregate([{ $match: { createdAt: { $gte: since } } }, { $group: { _id: '$status', n: { $sum: 1 }, total: { $sum: '$total' } } }]),
      PaymentModel.aggregate([{ $match: { createdAt: { $gte: since } } }, { $group: { _id: null, n: { $sum: 1 }, sum: { $sum: '$amount' } } }]),
      RefundModel.aggregate([{ $match: { createdAt: { $gte: since } } }, { $group: { _id: null, sum: { $sum: '$amount' } } }]),
      SessionModel.aggregate([{ $match: { lastSeenAt: { $gte: new Date(Date.now() - 5*60*1000) } } }, { $count: 'n' }]),
      SupportTicketModel.aggregate([{ $match: { status: 'open' } }, { $count: 'n' }]),
      AuditLogModel.aggregate([{ $match: { severity: 'critical', createdAt: { $gte: since } } }, { $count: 'n' }])
    ]);
    res.json({ newUsers: users[0]?.n ?? 0, ordersByStatus: orders, paymentsTotal: payments[0]?.sum ?? 0, refundsTotal: refunds[0]?.sum ?? 0, activeNow: sessions[0]?.n ?? 0, openTickets: tickets[0]?.n ?? 0, criticalAlerts: audits[0]?.n ?? 0 });
  } catch (err) { next(err); }
};

import { Schema, model } from 'mongoose';

const AdminOverviewSchema = new Schema({
  _id: { type: String, default: 'singleton' },
  newUsers: { type: Number, default: 0 },
  ordersByStatus: { type: Map, of: new Schema({ n: Number, total: Number }, { _id: false }), default: {} },
  paymentsTotal: { type: Number, default: 0 },
  refundsTotal: { type: Number, default: 0 },
  activeNow: { type: Number, default: 0 },
  openTickets: { type: Number, default: 0 },
  criticalAlerts: { type: Number, default: 0 },
  lastUpdatedAt: { type: Date, default: () => new Date() }
}, { _id: false });

export const AdminOverviewModel = model('AdminOverview', AdminOverviewSchema);

import { OrderModel } from '../models/order.model';
import { PaymentModel } from '../models/payment.model';
import { AdminOverviewModel } from '../models/admin-overview.model';
import { ResumeTokenModel } from '../models/resume-token.model';
import type { ChangeStreamDocument } from 'mongodb';

async function watchCollection(name: string, model: any, handler: (doc: ChangeStreamDocument) => Promise<void>) {
  const saved = await ResumeTokenModel.findById(name).lean();
  const stream = model.watch([], { resumeAfter: saved?.token, fullDocument: 'updateLookup' });
  stream.on('change', async (event: ChangeStreamDocument) => {
    await handler(event);
    await ResumeTokenModel.updateOne({ _id: name }, { $set: { token: event._id } }, { upsert: true });
  });
  stream.on('error', (err: Error) => { console.error(`stream ${name} error`, err); setTimeout(() => watchCollection(name, model, handler), 2000); });
}

export async function startOverviewProjector() {
  await seedIfEmpty();
  await watchCollection('orders', OrderModel, async (event) => {
    if (event.operationType === 'insert') {
      const status = (event.fullDocument as any).status;
      const total = (event.fullDocument as any).total;
      await AdminOverviewModel.updateOne({ _id: 'singleton' }, { $inc: { [`ordersByStatus.${status}.n`]: 1, [`ordersByStatus.${status}.total`]: total }, $set: { lastUpdatedAt: new Date() } });
    }
  });
  await watchCollection('payments', PaymentModel, async (event) => {
    if (event.operationType === 'insert') {
      const amount = (event.fullDocument as any).amount;
      await AdminOverviewModel.updateOne({ _id: 'singleton' }, { $inc: { paymentsTotal: amount }, $set: { lastUpdatedAt: new Date() } });
    }
  });
}

async function seedIfEmpty() {
  const exists = await AdminOverviewModel.findById('singleton').lean();
  if (exists) return;
  await AdminOverviewModel.create({ _id: 'singleton' });
}

import { Request, Response, NextFunction } from 'express';
import { AdminOverviewModel } from '../models/admin-overview.model';

export const getOverview = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const doc = await AdminOverviewModel.findById('singleton').lean();
    if (!doc) return res.json({ newUsers: 0, ordersByStatus: [], paymentsTotal: 0, refundsTotal: 0, activeNow: 0, openTickets: 0, criticalAlerts: 0 });
    const ordersByStatus = Object.entries(doc.ordersByStatus ?? {}).map(([status, v]: any) => ({ _id: status, n: v.n, total: v.total }));
    res.json({ newUsers: doc.newUsers, ordersByStatus, paymentsTotal: doc.paymentsTotal, refundsTotal: doc.refundsTotal, activeNow: doc.activeNow, openTickets: doc.openTickets, criticalAlerts: doc.criticalAlerts, _staleness: Date.now() - new Date(doc.lastUpdatedAt).getTime() });
  } catch (err) { next(err); }
};

import { useEffect, useState } from 'react';
import { fetchOverview, type Overview } from './api';

export function Dashboard() {
  const [data, setData] = useState<Overview | null>(null);
  const [stalenessMs, setStalenessMs] = useState(0);
  useEffect(() => {
    let cancelled = false;
    const tick = async () => {
      const res = await fetchOverview();
      if (cancelled) return;
      setData(res);
      setStalenessMs(res._staleness ?? 0);
    };
    tick();
    const id = setInterval(tick, 5000);
    return () => { cancelled = true; clearInterval(id); };
  }, []);
  if (!data) return <div>Loading...</div>;
  return (
    <div className="grid grid-cols-4 gap-4">
      {stalenessMs > 5000 && <div className="col-span-4 bg-yellow-100 p-2">Data is {Math.round(stalenessMs/1000)}s behind</div>}
      <Kpi label="New users" value={data.newUsers} />
      <Kpi label="Payments" value={`$${data.paymentsTotal.toLocaleString()}`} />
      <Kpi label="Active now" value={data.activeNow} />
      <Kpi label="Critical alerts" value={data.criticalAlerts} />
    </div>
  );
}

function Kpi({ label, value }: { label: string; value: string | number }) {
  return <div className="p-4 rounded-lg bg-white shadow"><div className="text-sm text-gray-500">{label}</div><div className="text-2xl font-semibold">{value}</div></div>;
}

import { Request, Response, NextFunction } from 'express';
import { UserModel } from '../models/user.model';

export const updateUser = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { id } = req.params;
    const updated = await UserModel.findByIdAndUpdate(id, { $set: req.body }, { new: true });
    if (!updated) return res.status(404).json({ error: 'NOT_FOUND' });
    res.json({ user: updated });
  } catch (err) { next(err); }
};

import { Request, Response, NextFunction } from 'express';
import { ProfileModel } from '../models/profile.model';

export const updateProfile = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const userId = req.user!.id;
    const updated = await ProfileModel.findOneAndUpdate({ userId }, { $set: req.body }, { new: true, upsert: true });
    res.json({ profile: updated });
  } catch (err) { next(err); }
};

import { useState } from 'react';
import { updateProfile } from '../../api/profile';

export function EditProfile({ initial }: { initial: { displayName: string; bio: string } }) {
  const [form, setForm] = useState(initial);
  return (
    <form onSubmit={async (e) => { e.preventDefault(); await updateProfile(form); }}>
      <input value={form.displayName} onChange={e => setForm({ ...form, displayName: e.target.value })} />
      <textarea value={form.bio} onChange={e => setForm({ ...form, bio: e.target.value })} />
      <button type="submit">Save</button>
    </form>
  );
}

import { z } from 'zod';

export const userUpdateSelfSchema = z.object({
  email: z.string().email().optional(),
  displayName: z.string().min(1).max(50).optional()
}).strict();

export const userUpdateAdminSchema = userUpdateSelfSchema.extend({
  role: z.enum(['user','admin','support']).optional(),
  suspended: z.boolean().optional()
}).strict();

export type UserUpdateSelf = z.infer<typeof userUpdateSelfSchema>;
export type UserUpdateAdmin = z.infer<typeof userUpdateAdminSchema>;

import { Request, Response, NextFunction } from 'express';
import { ZodSchema, ZodError } from 'zod';
import { HttpError } from '../errors/http-error';

export function validateBody<T>(schema: ZodSchema<T>) {
  return (req: Request, _res: Response, next: NextFunction) => {
    try {
      const parsed = schema.parse(req.body);
      req.body = parsed;
      next();
    } catch (err) {
      if (err instanceof ZodError) {
        return next(new HttpError(400, 'VALIDATION_FAILED', { issues: err.issues }));
      }
      next(err);
    }
  };
}

import { Request, Response, NextFunction } from 'express';
import { UserModel } from '../models/user.model';
import { HttpError } from '../errors/http-error';
import { auditLog } from '../services/audit.service';
import type { UserUpdateSelf, UserUpdateAdmin } from '../../shared/schemas/user.schema';

export const updateUser = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const targetId = req.params.id;
    const actor = req.user!;
    const isSelf = actor.id === targetId;
    const isAdmin = actor.role === 'admin';
    if (!isSelf && !isAdmin) throw new HttpError(403, 'FORBIDDEN');
    const body = req.body as UserUpdateSelf | UserUpdateAdmin;
    const before = await UserModel.findById(targetId).lean();
    if (!before) throw new HttpError(404, 'NOT_FOUND');
    const updated = await UserModel.findByIdAndUpdate(targetId, { $set: body }, { new: true });
    await auditLog({ actorId: actor.id, action: 'user.update', targetId, before, after: updated!.toObject() });
    res.json({ user: updated });
  } catch (err) { next(err); }
};

import { Router } from 'express';
import { requireAuth, requireRole } from '../middleware/auth';
import { validateBody } from '../middleware/validate-body';
import { userUpdateSelfSchema, userUpdateAdminSchema } from '../../shared/schemas/user.schema';
import { updateUser } from '../controllers/user.controller';

export const userRouter = Router();

userRouter.patch('/users/:id', requireAuth, (req, res, next) => {
  const schema = req.user!.role === 'admin' ? userUpdateAdminSchema : userUpdateSelfSchema;
  return validateBody(schema)(req, res, next);
}, updateUser);

import { useState } from 'react';
import { profileUpdateSchema, type ProfileUpdate } from '../../../shared/schemas/profile.schema';
import { updateProfile } from '../../api/profile';

export function EditProfile({ initial }: { initial: ProfileUpdate }) {
  const [form, setForm] = useState<ProfileUpdate>(initial);
  const [errors, setErrors] = useState<Record<string, string>>({});
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const parsed = profileUpdateSchema.safeParse(form);
    if (!parsed.success) {
      const fieldErrors: Record<string, string> = {};
      for (const issue of parsed.error.issues) fieldErrors[issue.path.join('.')] = issue.message;
      setErrors(fieldErrors);
      return;
    }
    setErrors({});
    await updateProfile(parsed.data);
  };
  return (
    <form onSubmit={handleSubmit}>
      <input value={form.displayName ?? ''} maxLength={50} onChange={e => setForm({ ...form, displayName: e.target.value })} />
      {errors.displayName && <span className="text-red-600">{errors.displayName}</span>}
      <textarea value={form.bio ?? ''} maxLength={500} onChange={e => setForm({ ...form, bio: e.target.value })} />
      {errors.bio && <span className="text-red-600">{errors.bio}</span>}
      <button type="submit">Save</button>
    </form>
  );
}

import { createContext, useContext, useState, ReactNode } from 'react';

type Item = { productId: string; quantity: number; unitPrice: number };
type Ctx = { items: Item[]; add: (i: Item) => void; remove: (productId: string) => void };
const CartItemsContext = createContext<Ctx | null>(null);

export function CartItemsProvider({ children }: { children: ReactNode }) {
  const [items, setItems] = useState<Item[]>([]);
  const add = (i: Item) => setItems(prev => [...prev, i]);
