export type CartItem = { productId: string; quantity: number; unitPrice: number };
export type CartState = { items: CartItem[] };

type Listener = () => void;

const STORAGE_KEY = 'cart.v2';

function load(): CartState {
  if (typeof window === 'undefined') return { items: [] };
  try { const raw = window.localStorage.getItem(STORAGE_KEY); return raw ? (JSON.parse(raw) as CartState) : { items: [] }; } catch { return { items: [] }; }
}

let state: CartState = load();
const listeners = new Set<Listener>();

function emit() { for (const l of listeners) l(); }

let persistTimer: ReturnType<typeof setTimeout> | null = null;
function schedulePersist() {
  if (persistTimer) clearTimeout(persistTimer);
  persistTimer = setTimeout(() => { try { window.localStorage.setItem(STORAGE_KEY, JSON.stringify(state)); } catch {} }, 200);
}

export const cartStore = {
  getState: (): CartState => state,
  subscribe: (l: Listener): (() => void) => { listeners.add(l); return () => { listeners.delete(l); }; },
  add(item: CartItem) {
    const existing = state.items.find(i => i.productId === item.productId);
    const nextItems = existing
      ? state.items.map(i => i.productId === item.productId ? { ...i, quantity: i.quantity + item.quantity } : i)
      : [...state.items, item];
    state = { items: nextItems };
    emit(); schedulePersist();
  },
  remove(productId: string) {
    state = { items: state.items.filter(i => i.productId !== productId) };
    emit(); schedulePersist();
  },
  setQuantity(productId: string, quantity: number) {
    state = { items: quantity <= 0 ? state.items.filter(i => i.productId !== productId) : state.items.map(i => i.productId === productId ? { ...i, quantity } : i) };
    emit(); schedulePersist();
  },
  clear() { state = { items: [] }; emit(); schedulePersist(); }
};

import { useSyncExternalStore } from 'react';
import { cartStore, type CartItem } from './store';

function useStoreSlice<T>(selector: (s: { items: CartItem[] }) => T, isEqual: (a: T, b: T) => boolean = Object.is): T {
  // useSyncExternalStore requires a stable snapshot - cache last result for ref equality on identical slices
  let lastSnap: T;
  let lastState: { items: CartItem[] } | null = null;
  const getSnapshot = () => {
    const s = cartStore.getState();
    if (lastState === s) return lastSnap;
    const next = selector(s);
    if (lastState !== null && isEqual(lastSnap, next)) { lastState = s; return lastSnap; }
    lastState = s; lastSnap = next; return next;
  };
  return useSyncExternalStore(cartStore.subscribe, getSnapshot, getSnapshot);
}

export const useCartItems = () => useStoreSlice(s => s.items);
export const useCartBadge = () => useStoreSlice(s => s.items.reduce((n, i) => n + i.quantity, 0));
export const useCartTotal = () => useStoreSlice(s => s.items.reduce((t, i) => t + i.quantity * i.unitPrice, 0));
export const useCartActions = () => ({ add: cartStore.add, remove: cartStore.remove, setQuantity: cartStore.setQuantity, clear: cartStore.clear });

