import { Server, Socket } from 'socket.io';
import { verifyJwt } from '../auth/jwt';

type CursorPayload = { line: number; col: number; selection?: { startLine: number; startCol: number; endLine: number; endCol: number } };
interface AuthedSocket extends Socket { data: { userId: string; displayName: string; color: string; lastEmit: number; tokenBucket: number } }

const RATE_LIMIT_HZ = 20;
const BUCKET_CAPACITY = 30;

function colorForUser(userId: string): string {
  let hash = 0;
  for (const ch of userId) hash = (hash * 31 + ch.charCodeAt(0)) & 0xffffffff;
  const hue = Math.abs(hash) % 360;
  return `hsl(${hue} 70% 50%)`;
}

export function attachDocumentNamespace(io: Server) {
  const ns = io.of('/document');
  ns.use(async (socket, next) => {
    try {
      const token = socket.handshake.auth.token as string | undefined;
      if (!token) return next(new Error('UNAUTHENTICATED'));
      const { sub, name } = await verifyJwt(token);
      const s = socket as AuthedSocket;
      s.data.userId = sub; s.data.displayName = name ?? sub.slice(0,6); s.data.color = colorForUser(sub); s.data.lastEmit = 0; s.data.tokenBucket = BUCKET_CAPACITY;
      next();
    } catch { next(new Error('UNAUTHENTICATED')); }
  });
  ns.on('connection', (socket: AuthedSocket) => {
    socket.on('doc:join', (docId: string) => {
      socket.join(`doc:${docId}`);
      socket.to(`doc:${docId}`).emit('peer:join', { userId: socket.data.userId, displayName: socket.data.displayName, color: socket.data.color });
      const peers = Array.from(ns.adapter.rooms.get(`doc:${docId}`) ?? []).map(sid => { const s = ns.sockets.get(sid) as AuthedSocket | undefined; return s ? { userId: s.data.userId, displayName: s.data.displayName, color: s.data.color } : null; }).filter(Boolean);
      socket.emit('peer:list', peers);
    });
    socket.on('cursor:move', (docId: string, payload: CursorPayload) => {
      const now = Date.now();
      const elapsed = (now - socket.data.lastEmit) / 1000;
      socket.data.tokenBucket = Math.min(BUCKET_CAPACITY, socket.data.tokenBucket + elapsed * RATE_LIMIT_HZ);
      socket.data.lastEmit = now;
      if (socket.data.tokenBucket < 1) return;
      socket.data.tokenBucket -= 1;
      socket.to(`doc:${docId}`).emit('cursor:update', { userId: socket.data.userId, ...payload, at: now });
    });
    socket.on('disconnect', () => {
      for (const room of socket.rooms) if (room.startsWith('doc:')) ns.to(room).emit('peer:leave', { userId: socket.data.userId });
    });
  });
}

import { useEffect, useRef, useState } from 'react';
import { io, Socket } from 'socket.io-client';

export type Peer = { userId: string; displayName: string; color: string };
export type RemoteCursor = { userId: string; line: number; col: number; targetLine: number; targetCol: number; lastSeen: number; opacity: number; color: string; displayName: string };

export function useCollaborativeCursors(docId: string, token: string) {
  const [peers, setPeers] = useState<Peer[]>([]);
  const cursorsRef = useRef<Map<string, RemoteCursor>>(new Map());
  const [, force] = useState(0);
  const socketRef = useRef<Socket | null>(null);
  const lastEmitRef = useRef(0);

  useEffect(() => {
    const socket = io('/document', { auth: { token }, transports: ['websocket'] });
    socketRef.current = socket;
    socket.on('connect', () => socket.emit('doc:join', docId));
    socket.on('peer:list', (list: Peer[]) => setPeers(list.filter(p => p)));
    socket.on('peer:join', (p: Peer) => setPeers(prev => [...prev.filter(x => x.userId !== p.userId), p]));
    socket.on('peer:leave', ({ userId }: { userId: string }) => {
      setPeers(prev => prev.filter(p => p.userId !== userId));
      cursorsRef.current.delete(userId);
      force(n => n + 1);
    });
    socket.on('cursor:update', (u: { userId: string; line: number; col: number; at: number }) => {
      const peer = (peers.find(p => p.userId === u.userId) ?? { color: 'gray', displayName: u.userId.slice(0,6) });
      const existing = cursorsRef.current.get(u.userId);
      cursorsRef.current.set(u.userId, {
        userId: u.userId,
        line: existing?.line ?? u.line,
        col: existing?.col ?? u.col,
        targetLine: u.line,
        targetCol: u.col,
        lastSeen: Date.now(),
        opacity: 1,
        color: peer.color,
        displayName: peer.displayName
      });
    });
    return () => { socket.removeAllListeners(); socket.disconnect(); };
  }, [docId, token]);

  useEffect(() => {
    let raf = 0;
    const tick = () => {
      const now = Date.now();
      let mutated = false;
      for (const [id, c] of cursorsRef.current) {
        const dl = c.targetLine - c.line; const dc = c.targetCol - c.col;
        if (Math.abs(dl) > 0.01 || Math.abs(dc) > 0.01) { c.line += dl * 0.25; c.col += dc * 0.25; mutated = true; }
        const age = now - c.lastSeen;
        const desired = age > 5000 ? 0 : age > 3000 ? Math.max(0, 1 - (age - 3000) / 2000) : 1;
        if (Math.abs(desired - c.opacity) > 0.01) { c.opacity += (desired - c.opacity) * 0.2; mutated = true; }
        if (age > 6000) { cursorsRef.current.delete(id); mutated = true; }
      }
      if (mutated) force(n => n + 1);
      raf = requestAnimationFrame(tick);
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, []);

  const emitCursor = (line: number, col: number) => {
    const now = Date.now();
    if (now - lastEmitRef.current < 50) return;
    lastEmitRef.current = now;
    socketRef.current?.emit('cursor:move', docId, { line, col });
  };

  return { peers, cursors: Array.from(cursorsRef.current.values()), emitCursor };
}

import { useRef, useState } from 'react';
import { useCollaborativeCursors } from './useCollaborativeCursors';

export function DocumentEditor({ docId, token, initialContent }: { docId: string; token: string; initialContent: string }) {
  const [content, setContent] = useState(initialContent);
  const taRef = useRef<HTMLTextAreaElement>(null);
  const { cursors, peers, emitCursor } = useCollaborativeCursors(docId, token);

  const reportCursor = () => {
    const ta = taRef.current; if (!ta) return;
    const pos = ta.selectionStart;
    const upto = ta.value.slice(0, pos);
    const line = upto.split('\n').length - 1;
    const col = pos - upto.lastIndexOf('\n') - 1;
    emitCursor(line, col);
  };

  return (
    <div className="relative">
      <div className="flex gap-1 mb-2">{peers.map(p => <span key={p.userId} className="text-xs px-2 py-0.5 rounded" style={{ background: p.color, color: 'white' }}>{p.displayName}</span>)}</div>
      <textarea ref={taRef} className="w-full h-96 p-4 font-mono leading-6" value={content} onChange={e => { setContent(e.target.value); reportCursor(); }} onKeyUp={reportCursor} onClick={reportCursor} />
      <div className="pointer-events-none absolute inset-0 p-4 font-mono leading-6">
        {cursors.map(c => (
          <span key={c.userId} className="absolute transition-opacity" style={{ top: c.line * 24, left: c.col * 9.6, opacity: c.opacity, borderLeft: `2px solid ${c.color}`, height: 24 }}>
            <span className="absolute -top-5 left-0 text-xs px-1 rounded" style={{ background: c.color, color: 'white' }}>{c.displayName}</span>
          </span>
        ))}
      </div>
    </div>
  );
}

