export function startSensorBroadcaster(io: Server) {
  const ns = io.of('/sensors');
  const pending = new Map<string, Update>();
  const stream = SensorReadingModel.watch([{ $match: { operationType: 'insert' } }], { fullDocument: 'updateLookup' });
  stream.on('change', (event: any) => {
    const doc = event.fullDocument;
    pending.set(String(doc.sensorId), { sensorId: String(doc.sensorId), temperature: doc.temperature, humidity: doc.humidity, at: Date.now() });
  });
  setInterval(() => {
    if (pending.size === 0) return;
    const batch = Array.from(pending.values());
    pending.clear();
    ns.emit('sensors:batch', batch);
  }, 1000);
  ns.on('connection', socket => {
    socket.on('disconnect', () => {});
  });
}

