import { useEffect, useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { io, Socket } from 'socket.io-client';
import { useSensorPositions } from './useSensorPositions';

const MAX_SENSORS = 6000;
const tempMatrix = new THREE.Matrix4();
const tempColor = new THREE.Color();

function tempToColor(t: number): THREE.Color {
  const clamped = Math.max(-10, Math.min(40, t));
  const norm = (clamped + 10) / 50;
  return tempColor.setHSL((1 - norm) * 0.66, 0.85, 0.5);
}

export function Sensors({ token }: { token: string }) {
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const positions = useSensorPositions();
  const indexBySensor = useRef<Map<string, number>>(new Map());
  const dirty = useRef<Set<number>>(new Set());
  const socketRef = useRef<Socket | null>(null);

  useEffect(() => {
    const mesh = meshRef.current; if (!mesh) return;
    positions.forEach((pos, i) => {
      tempMatrix.setPosition(pos.x, pos.y, pos.z);
      mesh.setMatrixAt(i, tempMatrix);
      mesh.setColorAt(i, tempToColor(20));
      indexBySensor.current.set(pos.sensorId, i);
    });
    mesh.instanceMatrix.needsUpdate = true;
    if (mesh.instanceColor) mesh.instanceColor.needsUpdate = true;
    mesh.count = positions.length;
  }, [positions]);

  useEffect(() => {
    const socket = io('/sensors', { auth: { token }, transports: ['websocket'] });
    socketRef.current = socket;
    socket.on('sensors:batch', (batch: { sensorId: string; temperature: number }[]) => {
      const mesh = meshRef.current; if (!mesh) return;
      for (const u of batch) {
        const idx = indexBySensor.current.get(u.sensorId);
        if (idx === undefined) continue;
        mesh.setColorAt(idx, tempToColor(u.temperature));
        dirty.current.add(idx);
      }
    });
    return () => { socket.removeAllListeners(); socket.disconnect(); };
  }, [token]);

  useFrame(() => {
    const mesh = meshRef.current; if (!mesh) return;
    if (dirty.current.size > 0 && mesh.instanceColor) {
      mesh.instanceColor.needsUpdate = true;
      dirty.current.clear();
    }
  });

  useEffect(() => () => {
    const mesh = meshRef.current;
    if (mesh) { mesh.geometry.dispose(); (mesh.material as THREE.Material).dispose(); }
  }, []);

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, MAX_SENSORS]}>
      <sphereGeometry args={[0.3, 12, 8]} />
      <meshStandardMaterial />
    </instancedMesh>
  );
}

