export function getTenantContext(): TenantContext {
  const ctx = storage.getStore();
  if (!ctx) throw new Error('TENANT_CONTEXT_MISSING - call from inside tenant middleware');
  return ctx;
}

export async function tenantContext(req: Request, _res: Response, next: NextFunction) {
  try {
    const userId = req.user?.id;
    if (!userId) throw new HttpError(401, 'UNAUTHENTICATED');
    const orgId = (req.headers['x-org-id'] as string | undefined) ?? req.user?.defaultOrgId;
    if (!orgId) throw new HttpError(400, 'ORG_ID_REQUIRED');
    const membership = await MembershipModel.findOne({ userId, orgId }).lean();
    if (!membership) throw new HttpError(403, 'NOT_A_MEMBER');
    storage.run({ userId, orgId, role: membership.role }, () => next());
  } catch (err) { next(err); }
}

