export const login = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { email, password } = req.body;
    const user = await UserModel.findOne({ email });
    if (!user) return res.status(401).json({ error: 'INVALID_CREDENTIALS' });
    const ok = await bcrypt.compare(password, user.passwordHash);
    if (!ok) return res.status(401).json({ error: 'INVALID_CREDENTIALS' });
    const token = jwt.sign({ sub: user._id.toString() }, process.env.JWT_SECRET!, { expiresIn: '15m' });
    const refresh = jwt.sign({ sub: user._id.toString(), type: 'refresh' }, process.env.JWT_SECRET!, { expiresIn: '30d' });
    res.cookie('rt', refresh, { httpOnly: true, sameSite: 'strict', secure: true });
    res.json({ token, user: { id: user._id, email: user.email, displayName: user.displayName } });
  } catch (err) { next(err); }
};

