import bcrypt from 'bcrypt';
import { IdentityModel } from '../../models/identity.model';
import { UserModel } from '../../models/user.model';
import type { Types } from 'mongoose';

export interface AuthResult { userId: Types.ObjectId }
export interface AuthStrategy { authenticate(input: unknown): Promise<AuthResult> }

export class PasswordStrategy implements AuthStrategy {
  async authenticate(input: unknown): Promise<AuthResult> {
    const { email, password } = input as { email: string; password: string };
    const user = await UserModel.findOne({ email });
    if (!user) throw new Error('INVALID_CREDENTIALS');
    const identity = await IdentityModel.findOne({ userId: user._id, type: 'password' });
    if (!identity?.passwordHash) throw new Error('INVALID_CREDENTIALS');
    const ok = await bcrypt.compare(password, identity.passwordHash);
    if (!ok) throw new Error('INVALID_CREDENTIALS');
    return { userId: user._id };
  }
}

export class OidcStrategy implements AuthStrategy {
  constructor(private readonly providerId: string, private readonly verifyIdToken: (token: string) => Promise<{ sub: string; email: string; name?: string }>) {}
  async authenticate(input: unknown): Promise<AuthResult> {
    const { idToken } = input as { idToken: string };
    const claims = await this.verifyIdToken(idToken);
    let identity = await IdentityModel.findOne({ type: 'oidc', providerId: this.providerId, subject: claims.sub });
    if (!identity) {
      let user = await UserModel.findOne({ email: claims.email });
      if (!user) user = await UserModel.create({ email: claims.email, displayName: claims.name ?? claims.email });
      identity = await IdentityModel.create({ userId: user._id, type: 'oidc', providerId: this.providerId, subject: claims.sub });
    }
    return { userId: identity.userId };
  }
}

import { Request, Response, NextFunction } from 'express';
import { issueTokens } from '../services/auth/tokens';
import { PasswordStrategy, OidcStrategy } from '../services/auth/strategies';
import { resolveProviderForEmail, getOidcProvider } from '../services/auth/providers';
import { HttpError } from '../errors/http-error';

const passwordStrategy = new PasswordStrategy();

export const discover = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { email } = req.body as { email: string };
    const provider = await resolveProviderForEmail(email);
    if (provider.type === 'password') return res.json({ type: 'password' });
    return res.json({ type: 'oidc', authorizeUrl: provider.authorizeUrl });
  } catch (err) { next(err); }
};

export const passwordLogin = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { userId } = await passwordStrategy.authenticate(req.body);
    const tokens = await issueTokens(userId);
    res.cookie('rt', tokens.refresh, { httpOnly: true, sameSite: 'strict', secure: true });
    res.json({ token: tokens.access, user: await loadPublicUser(userId) });
  } catch (err) {
    if (err instanceof Error && err.message === 'INVALID_CREDENTIALS') return next(new HttpError(401, 'INVALID_CREDENTIALS'));
    next(err);
  }
};

export const oidcCallback = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { providerId, idToken } = req.body as { providerId: string; idToken: string };
    const provider = getOidcProvider(providerId);
    const strategy = new OidcStrategy(providerId, provider.verifyIdToken);
    const { userId } = await strategy.authenticate({ idToken });
    const tokens = await issueTokens(userId);
    res.cookie('rt', tokens.refresh, { httpOnly: true, sameSite: 'strict', secure: true });
    res.json({ token: tokens.access, user: await loadPublicUser(userId) });
  } catch (err) { next(err); }
};

async function loadPublicUser(userId: import('mongoose').Types.ObjectId) {
  const { UserModel } = await import('../models/user.model');
  const u = await UserModel.findById(userId).lean();
  return u ? { id: u._id, email: u.email, displayName: u.displayName } : null;
}

