export const feedService = {
  async getFeed(cursor?: string, limit = 50) {
    const filter: Record<string, unknown> = {};
    if (cursor) filter.createdAt = { $lt: new Date(cursor) };
    const posts = await PostModel.find(filter).sort({ createdAt: -1 }).limit(limit).lean();
    const enriched = await Promise.all(posts.map(async p => {
      const author = await UserModel.findById(p.authorId).lean();
