import { PostModel } from '../models/post.model';
import type { PipelineStage } from 'mongoose';

export const feedService = {
  async getFeed(cursor?: string, limit = 50) {
    const match: PipelineStage.Match = { $match: cursor ? { createdAt: { $lt: new Date(cursor) } } : {} };
    const pipeline: PipelineStage[] = [
      match,
      { $sort: { createdAt: -1 } },
      { $limit: limit },
      { $lookup: { from: 'users', localField: 'authorId', foreignField: '_id', as: 'authorArr', pipeline: [{ $project: { displayName: 1, avatar: 1 } }] } },
      { $lookup: { from: 'comments', let: { postId: '$_id' }, pipeline: [{ $match: { $expr: { $eq: ['$postId', '$$postId'] } } }, { $count: 'n' }], as: 'commentAgg' } },
      { $lookup: { from: 'likes', let: { postId: '$_id' }, pipeline: [{ $match: { $expr: { $eq: ['$postId', '$$postId'] } } }, { $count: 'n' }], as: 'likeAgg' } },
      { $addFields: {
        author: { $let: { vars: { a: { $arrayElemAt: ['$authorArr', 0] } }, in: { id: '$$a._id', displayName: '$$a.displayName', avatar: '$$a.avatar' } } },
        commentCount: { $ifNull: [{ $arrayElemAt: ['$commentAgg.n', 0] }, 0] },
        likeCount: { $ifNull: [{ $arrayElemAt: ['$likeAgg.n', 0] }, 0] }
      } },
      { $project: { authorArr: 0, commentAgg: 0, likeAgg: 0 } }
    ];
    return PostModel.aggregate(pipeline);
  }
};

import { useEffect, useRef, useState, useCallback } from 'react';
import { useVirtualizer } from '@tanstack/react-virtual';
import { fetchFeed } from '../../api/feed';
import { PostCard } from './PostCard';

type Post = { _id: string; content: string; author: { id: string; displayName: string }; commentCount: number; likeCount: number; createdAt: string };

export function FeedList() {
  const parentRef = useRef<HTMLDivElement>(null);
  const [posts, setPosts] = useState<Post[]>([]);
  const [cursor, setCursor] = useState<string | undefined>();
  const [loading, setLoading] = useState(false);
  const [done, setDone] = useState(false);

  const loadMore = useCallback(async () => {
    if (loading || done) return;
    setLoading(true);
    const more = await fetchFeed(cursor);
    setPosts(prev => [...prev, ...more]);
    if (more.length === 0) setDone(true);
    else setCursor(more.at(-1)!.createdAt);
    setLoading(false);
  }, [cursor, loading, done]);

  useEffect(() => { loadMore(); }, []);

  const rowVirtualizer = useVirtualizer({
    count: posts.length + (done ? 0 : 1),
    getScrollElement: () => parentRef.current,
    estimateSize: () => 220,
    overscan: 5
  });

  useEffect(() => {
    const items = rowVirtualizer.getVirtualItems();
    const last = items.at(-1);
    if (last && last.index >= posts.length - 5) loadMore();
  }, [rowVirtualizer.getVirtualItems(), posts.length, loadMore]);

  return (
    <div ref={parentRef} className="h-screen overflow-auto">
      <div style={{ height: rowVirtualizer.getTotalSize(), position: 'relative' }}>
        {rowVirtualizer.getVirtualItems().map(v => {
          const post = posts[v.index];
          return (
            <div key={v.key} style={{ position: 'absolute', top: 0, left: 0, width: '100%', transform: `translateY(${v.start}px)` }}>
              {post ? <PostCard post={post} /> : <div className="p-4 text-center">Loading...</div>}
            </div>
          );
        })}
      </div>
    </div>
  );
}

