import cors from 'cors';

const allowed = (process.env.CORS_ORIGINS ?? '').split(',').map(s => s.trim()).filter(Boolean);

export const strictCors = cors({
  origin: (origin, cb) => {
    if (!origin) return cb(null, true); // same-origin or non-browser clients
    if (allowed.includes(origin)) return cb(null, true);
    cb(new Error('CORS_BLOCKED'));
  },
  credentials: true,
  methods: ['GET','POST','PUT','PATCH','DELETE','OPTIONS'],
  allowedHeaders: ['content-type','authorization','x-csrf-token']
});

export const publicCors = cors({ origin: '*', credentials: false, methods: ['GET','OPTIONS'] });

import { Request, Response, NextFunction } from 'express';
import crypto from 'node:crypto';
import { HttpError } from '../errors/http-error';

const SAFE_METHODS = new Set(['GET','HEAD','OPTIONS']);

export function csrfIssue(req: Request, res: Response, next: NextFunction) {
  if (!req.cookies['csrf']) {
    const token = crypto.randomBytes(32).toString('base64url');
    res.cookie('csrf', token, { sameSite: 'lax', secure: true, httpOnly: false, path: '/' });
  }
  next();
}

export function csrfVerify(req: Request, _res: Response, next: NextFunction) {
  if (SAFE_METHODS.has(req.method)) return next();
  // Bearer-token auth bypasses CSRF - no cookie-based session in use
  const authHeader = req.headers.authorization;
  if (authHeader?.startsWith('Bearer ')) return next();
  const cookieToken = req.cookies['csrf'];
  const headerToken = req.headers['x-csrf-token'];
  if (!cookieToken || !headerToken || cookieToken !== headerToken) return next(new HttpError(403, 'CSRF_MISMATCH'));
  next();
}

import express from 'express';
