import { accountRouter } from './routes/account.routes';
import { publicRouter } from './routes/public.routes';

const app = express();
app.use(helmet());
app.use(cookieParser(process.env.COOKIE_SECRET));
app.use(express.json({ limit: '1mb' }));

// Public read-only endpoints get permissive CORS, no CSRF
app.use('/api/public', publicCors, publicRouter);

// Authenticated routes get strict CORS, CSRF issuance/verification
app.use('/api', strictCors, csrfIssue, csrfVerify);
app.use('/api/auth', authRouter);
app.use('/api/account', accountRouter);

