import { useReducer, useCallback, useRef } from 'react';
import type { ZodSchema, ZodError } from 'zod';

type State<T> = { values: T; touched: Partial<Record<keyof T, boolean>>; errors: Partial<Record<keyof T, string>>; submitting: boolean; submitError: string | null; initial: T };

type Action<T> =
  | { type: 'SET_FIELD'; key: keyof T; value: T[keyof T] }
  | { type: 'SET_TOUCHED'; key: keyof T }
  | { type: 'START_SUBMIT' }
  | { type: 'SUBMIT_SUCCESS'; values: T }
  | { type: 'SUBMIT_ERROR'; error: string; fieldErrors?: Partial<Record<keyof T, string>> }
  | { type: 'RESET'; values: T };

function reducer<T>(state: State<T>, action: Action<T>): State<T> {
  switch (action.type) {
    case 'SET_FIELD': return { ...state, values: { ...state.values, [action.key]: action.value }, errors: { ...state.errors, [action.key]: undefined } };
    case 'SET_TOUCHED': return { ...state, touched: { ...state.touched, [action.key]: true } };
    case 'START_SUBMIT': return { ...state, submitting: true, submitError: null };
    case 'SUBMIT_SUCCESS': return { ...state, submitting: false, initial: action.values, values: action.values };
    case 'SUBMIT_ERROR': return { ...state, submitting: false, submitError: action.error, errors: { ...state.errors, ...(action.fieldErrors ?? {}) } };
    case 'RESET': return { values: action.values, initial: action.values, touched: {}, errors: {}, submitting: false, submitError: null };
  }
}

export function useForm<T extends Record<string, unknown>>(initial: T, schema: ZodSchema<T>, onSubmit: (values: T) => Promise<T>) {
  const [state, dispatch] = useReducer(reducer<T>, { values: initial, initial, touched: {}, errors: {}, submitting: false, submitError: null });
  const stateRef = useRef(state); stateRef.current = state;

  const setField = useCallback(<K extends keyof T>(key: K, value: T[K]) => dispatch({ type: 'SET_FIELD', key, value }), []);
  const touch = useCallback((key: keyof T) => dispatch({ type: 'SET_TOUCHED', key }), []);
  const isDirty = JSON.stringify(state.values) !== JSON.stringify(state.initial);

  const submit = useCallback(async () => {
    const parsed = schema.safeParse(stateRef.current.values);
    if (!parsed.success) {
      const fieldErrors: Partial<Record<keyof T, string>> = {};
      for (const issue of (parsed.error as ZodError).issues) fieldErrors[issue.path[0] as keyof T] = issue.message;
      dispatch({ type: 'SUBMIT_ERROR', error: 'VALIDATION', fieldErrors });
      return;
    }
    dispatch({ type: 'START_SUBMIT' });
    try {
      const saved = await onSubmit(parsed.data);
      dispatch({ type: 'SUBMIT_SUCCESS', values: saved });
    } catch (e) {
      dispatch({ type: 'SUBMIT_ERROR', error: e instanceof Error ? e.message : 'UNKNOWN' });
    }
  }, [schema, onSubmit]);

  return { values: state.values, errors: state.errors, touched: state.touched, submitting: state.submitting, submitError: state.submitError, isDirty, setField, touch, submit };
}

