  const { values, errors, touched, submitting, submitError, isDirty, setField, touch, submit } = useForm<Settings>(initial, settingsSchema, async v => { const r = await saveSettings(v); return r.settings; });

  useEffect(() => {
    const handler = (e: BeforeUnloadEvent) => { if (isDirty) { e.preventDefault(); e.returnValue = ''; } };
    window.addEventListener('beforeunload', handler);
    return () => window.removeEventListener('beforeunload', handler);
  }, [isDirty]);

  return (
    <form onSubmit={e => { e.preventDefault(); submit(); }} className="space-y-4 max-w-lg">
      <Field label="Display name" error={touched.displayName ? errors.displayName : undefined}>
        <input className="border rounded p-2 w-full" value={values.displayName} onChange={e => setField('displayName', e.target.value)} onBlur={() => touch('displayName')} />
      </Field>
      <Field label="Bio" error={touched.bio ? errors.bio : undefined}>
        <textarea className="border rounded p-2 w-full" value={values.bio ?? ''} onChange={e => setField('bio', e.target.value)} onBlur={() => touch('bio')} />
      </Field>
      <label className="flex items-center gap-2">
        <input type="checkbox" checked={values.notifications.email} onChange={e => setField('notifications', { ...values.notifications, email: e.target.checked })} />
        Email notifications
      </label>
      {submitError && <div className="text-red-600">{submitError}</div>}
      <button type="submit" disabled={submitting || !isDirty} className="px-4 py-2 bg-black text-white rounded disabled:opacity-50">{submitting ? 'Saving...' : 'Save'}</button>
    </form>
  );
}

function Field({ label, error, children }: { label: string; error?: string; children: React.ReactNode }) {
  return <div><div className="text-sm font-medium">{label}</div>{children}{error && <div className="text-red-600 text-xs">{error}</div>}</div>;
}

import { Router, Request, Response } from 'express';
import bcrypt from 'bcrypt';
import jwt from 'jsonwebtoken';
import { UserModel } from './models/user.model';
import { z } from 'zod';

const router = Router();

router.post('/register', async (req: Request, res: Response) => {
  const schema = z.object({ email: z.string().email(), password: z.string().min(8), displayName: z.string().min(1) });
  const parsed = schema.safeParse(req.body);
  if (!parsed.success) return res.status(400).json({ error: 'VALIDATION', issues: parsed.error.issues });
  const exists = await UserModel.findOne({ email: parsed.data.email });
  if (exists) return res.status(409).json({ error: 'EMAIL_EXISTS' });
  const hash = await bcrypt.hash(parsed.data.password, 12);
  const user = await UserModel.create({ email: parsed.data.email, passwordHash: hash, displayName: parsed.data.displayName });
  const token = jwt.sign({ sub: user._id.toString() }, process.env.JWT_SECRET!, { expiresIn: '15m' });
  res.status(201).json({ token, user: { id: user._id, email: user.email, displayName: user.displayName } });
});

router.post('/login', async (req: Request, res: Response) => {
  const schema = z.object({ email: z.string().email(), password: z.string() });
  const parsed = schema.safeParse(req.body);
  if (!parsed.success) return res.status(400).json({ error: 'VALIDATION' });
  const user = await UserModel.findOne({ email: parsed.data.email });
  if (!user) return res.status(401).json({ error: 'INVALID' });
  const ok = await bcrypt.compare(parsed.data.password, user.passwordHash);
  if (!ok) return res.status(401).json({ error: 'INVALID' });
  const token = jwt.sign({ sub: user._id.toString() }, process.env.JWT_SECRET!, { expiresIn: '15m' });
  res.json({ token, user: { id: user._id, email: user.email, displayName: user.displayName } });
});

