import { Namespace, Socket } from 'socket.io';
import { redis } from '../infra/redis';

interface AuthedSocket extends Socket { data: { userId: string; typingTokens: number; typingLastRefill: number } }

const BUCKET_CAPACITY = 4;
const REFILL_PER_SECOND = 0.5;
const TTL_SECONDS = 4;

function consumeToken(socket: AuthedSocket): boolean {
  const now = Date.now();
  const elapsed = (now - socket.data.typingLastRefill) / 1000;
  socket.data.typingTokens = Math.min(BUCKET_CAPACITY, socket.data.typingTokens + elapsed * REFILL_PER_SECOND);
  socket.data.typingLastRefill = now;
  if (socket.data.typingTokens < 1) return false;
  socket.data.typingTokens -= 1;
  return true;
}

export function attachTypingHandlers(ns: Namespace) {
  ns.on('connection', (socket: AuthedSocket) => {
    socket.data.typingTokens = BUCKET_CAPACITY;
    socket.data.typingLastRefill = Date.now();
    socket.on('typing:start', async (roomId: string) => {
      if (!consumeToken(socket)) return;
      const key = `typing:${roomId}:${socket.data.userId}`;
      const isNew = (await redis.set(key, '1', { EX: TTL_SECONDS, NX: true })) === 'OK';
      await redis.expire(key, TTL_SECONDS);
      if (isNew) socket.to(`room:${roomId}`).emit('typing:update', { userId: socket.data.userId, typing: true });
    });
    socket.on('typing:stop', async (roomId: string) => {
      const key = `typing:${roomId}:${socket.data.userId}`;
      const deleted = await redis.del(key);
      if (deleted) socket.to(`room:${roomId}`).emit('typing:update', { userId: socket.data.userId, typing: false });
    });
    socket.on('disconnect', async () => {
      const pattern = `typing:*:${socket.data.userId}`;
      const keys = await redis.keys(pattern);
      for (const key of keys) {
        const roomId = key.split(':')[1];
        await redis.del(key);
        ns.to(`room:${roomId}`).emit('typing:update', { userId: socket.data.userId, typing: false });
      }
    });
  });
  setInterval(async () => {
    // sweep: emit stop for keys near expiration that haven't refreshed
    // For simplicity: Redis TTL itself disappears; we just need to notify peers.
    // Use keyspace notifications in prod; here we accept that clients receive next 'start' as a refresh.
  }, 5000);
}

import { useEffect, useRef, useState } from 'react';
import type { Socket } from 'socket.io-client';

export function useTypingIndicator(socket: Socket | null, roomId: string) {
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const stopTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const isTypingRef = useRef(false);
  const expiryByUser = useRef<Map<string, ReturnType<typeof setTimeout>>>(new Map());

  useEffect(() => {
    if (!socket) return;
    const onUpdate = ({ userId, typing }: { userId: string; typing: boolean }) => {
      setTypingUsers(prev => {
        const next = new Set(prev);
        if (typing) next.add(userId); else next.delete(userId);
        return next;
      });
      const existing = expiryByUser.current.get(userId);
      if (existing) clearTimeout(existing);
      if (typing) {
        const t = setTimeout(() => setTypingUsers(prev => { const n = new Set(prev); n.delete(userId); return n; }), 4500);
        expiryByUser.current.set(userId, t);
      } else {
        expiryByUser.current.delete(userId);
      }
    };
    socket.on('typing:update', onUpdate);
    return () => { socket.off('typing:update', onUpdate); for (const t of expiryByUser.current.values()) clearTimeout(t); };
  }, [socket]);

  const reportActivity = () => {
    if (!socket) return;
    if (!isTypingRef.current) { socket.emit('typing:start', roomId); isTypingRef.current = true; }
    if (stopTimer.current) clearTimeout(stopTimer.current);
    stopTimer.current = setTimeout(() => { socket.emit('typing:stop', roomId); isTypingRef.current = false; }, 3000);
  };

  return { typingUsers: Array.from(typingUsers), reportActivity };
}

