import { Request, Response, NextFunction } from 'express';
import { DeskModel } from '../models/desk.model';
import { io } from '../infra/socketio';
import { HttpError } from '../errors/http-error';

export const bookDesk = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { deskId } = req.params;
    const userId = req.user!.id;
    const result = await DeskModel.findOneAndUpdate({ _id: deskId, bookedBy: null }, { $set: { bookedBy: userId, bookedAt: new Date() } }, { new: true });
    if (!result) {
      const exists = await DeskModel.findById(deskId).lean();
      if (!exists) throw new HttpError(404, 'NOT_FOUND');
      throw new HttpError(409, 'ALREADY_BOOKED');
    }
    io.of('/desks').to(`floor:${result.floorId}`).emit('desk:booked', { deskId: result._id, userId, bookedAt: result.bookedAt });
    res.json({ desk: result });
  } catch (err) { next(err); }
};

export const releaseDesk = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { deskId } = req.params;
    const userId = req.user!.id;
    const result = await DeskModel.findOneAndUpdate({ _id: deskId, bookedBy: userId }, { $set: { bookedBy: null, bookedAt: null } }, { new: true });
    if (!result) throw new HttpError(403, 'NOT_OWNER');
    io.of('/desks').to(`floor:${result.floorId}`).emit('desk:released', { deskId });
    res.json({ desk: result });
  } catch (err) { next(err); }
};

