import { useMemo, useRef } from 'react';
import * as THREE from 'three';
import { ThreeEvent } from '@react-three/fiber';

export type DeskView = { _id: string; x: number; z: number; bookedBy: string | null; label: string };

const FREE = new THREE.Color('#5fbf6b');
const BOOKED = new THREE.Color('#d96b6b');
const MINE = new THREE.Color('#5f8ed9');

export function Desks({ desks, currentUserId, onBook, onRelease }: { desks: DeskView[]; currentUserId: string; onBook: (id: string) => void; onRelease: (id: string) => void }) {
  const meshRef = useRef<THREE.InstancedMesh>(null);
  useMemo(() => {
    const mesh = meshRef.current; if (!mesh) return;
    const m = new THREE.Matrix4();
    desks.forEach((d, i) => {
      m.makeTranslation(d.x, 0.5, d.z);
      mesh.setMatrixAt(i, m);
      const color = !d.bookedBy ? FREE : d.bookedBy === currentUserId ? MINE : BOOKED;
      mesh.setColorAt(i, color);
    });
    mesh.instanceMatrix.needsUpdate = true;
    if (mesh.instanceColor) mesh.instanceColor.needsUpdate = true;
    mesh.count = desks.length;
  }, [desks, currentUserId]);

  const handleClick = (e: ThreeEvent<MouseEvent>) => {
    if (e.instanceId === undefined) return;
    const desk = desks[e.instanceId];
    if (!desk) return;
    if (!desk.bookedBy) onBook(desk._id);
    else if (desk.bookedBy === currentUserId) onRelease(desk._id);
  };

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, 1000]} onClick={handleClick}>
      <boxGeometry args={[1.2, 0.6, 1.5]} />
      <meshStandardMaterial />
    </instancedMesh>
  );
}

import { useEffect, useState } from 'react';
import { io, Socket } from 'socket.io-client';
import type { DeskView } from './Desks';
import { bookDeskApi, releaseDeskApi, fetchFloorDesks } from '../../api/desks';

export function useDeskSocket(floorId: string, token: string, currentUserId: string) {
  const [desks, setDesks] = useState<DeskView[]>([]);

  useEffect(() => {
    fetchFloorDesks(floorId).then(setDesks);
    const socket: Socket = io('/desks', { auth: { token }, transports: ['websocket'] });
    socket.emit('floor:join', floorId);
    socket.on('desk:booked', ({ deskId, userId }) => setDesks(prev => prev.map(d => d._id === deskId ? { ...d, bookedBy: userId } : d)));
    socket.on('desk:released', ({ deskId }) => setDesks(prev => prev.map(d => d._id === deskId ? { ...d, bookedBy: null } : d)));
    return () => { socket.removeAllListeners(); socket.disconnect(); };
  }, [floorId, token]);

  const book = async (deskId: string) => {
    setDesks(prev => prev.map(d => d._id === deskId ? { ...d, bookedBy: currentUserId } : d));
    try { await bookDeskApi(deskId); } catch { fetchFloorDesks(floorId).then(setDesks); }
  };
  const release = async (deskId: string) => {
    setDesks(prev => prev.map(d => d._id === deskId ? { ...d, bookedBy: null } : d));
    try { await releaseDeskApi(deskId); } catch { fetchFloorDesks(floorId).then(setDesks); }
  };
  return { desks, book, release };
}

