type Theme = { primary: string; primaryHover: string; onPrimary: string; surface: string; ink: string };

function applyTheme(theme: Theme, target: HTMLElement = document.documentElement) {
  target.style.setProperty('--color-primary', theme.primary);
  target.style.setProperty('--color-primary-hover', theme.primaryHover);
  target.style.setProperty('--color-on-primary', theme.onPrimary);
  target.style.setProperty('--color-surface', theme.surface);
  target.style.setProperty('--color-ink', theme.ink);
}

export function ThemeProvider({ children }: { children: ReactNode }) {
