    if (!activeOrgId) return;
    let cancelled = false;
    fetch(`/api/org/${activeOrgId}/theme`, { credentials: 'include' }).then(r => r.json()).then((t: Theme) => { if (!cancelled) applyTheme(t); });
    return () => { cancelled = true; };
  }, [activeOrgId]);
  return <>{children}</>;
}

