  payload: { type: Schema.Types.Mixed, required: true },
  status: { type: String, enum: ['pending','processed','failed','dead'], default: 'pending', index: true },
  attempts: { type: Number, default: 0 },
  lastError: String,
  receivedAt: { type: Date, default: () => new Date() },
