import { Request, Response, NextFunction } from 'express';
import Stripe from 'stripe';
import { InboundEventModel } from '../models/inbound-event.model';

const stripe = new Stripe(process.env.STRIPE_KEY!);

export const stripeWebhook = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const sig = req.headers['stripe-signature'] as string;
    const event = stripe.webhooks.constructEvent(req.body as Buffer, sig, process.env.STRIPE_WEBHOOK_SECRET!);
    try {
      await InboundEventModel.create({ _id: event.id, source: 'stripe', type: event.type, payload: event });
    } catch (err: unknown) {
      // Duplicate key means we already received this event - that's fine, ack the retry
      if (!(err && typeof err === 'object' && 'code' in err && (err as { code: number }).code === 11000)) throw err;
    }
    res.json({ received: true });
  } catch (err) { next(err); }
};

import { startSession } from 'mongoose';
import { InboundEventModel } from '../models/inbound-event.model';
import { OrderModel } from '../models/order.model';
import { CreditModel } from '../models/credit.model';
import { IdempotencyKeyModel } from '../models/idempotency-key.model';
import type Stripe from 'stripe';

async function processOne(eventDoc: { _id: string; type: string; payload: Stripe.Event }) {
  const session = await startSession();
  try {
    await session.withTransaction(async () => {
      if (eventDoc.type === 'payment_intent.succeeded') {
        const intent = eventDoc.payload.data.object as Stripe.PaymentIntent;
        const idemKey = `stripe:${eventDoc._id}:order-paid`;
        const insertRes = await IdempotencyKeyModel.updateOne({ _id: idemKey }, { $setOnInsert: { createdAt: new Date() } }, { upsert: true, session });
        if (insertRes.upsertedCount === 0) return; // already processed
        await OrderModel.updateOne({ _id: intent.metadata.orderId }, { $set: { status: 'paid', paidAt: new Date() } }, { session });
        await CreditModel.create([{ userId: intent.metadata.userId, amount: intent.amount, source: 'stripe' }], { session });
      }
      await InboundEventModel.updateOne({ _id: eventDoc._id }, { $set: { status: 'processed', processedAt: new Date() }, $inc: { attempts: 1 } }, { session });
    });
  } catch (err) {
    await InboundEventModel.updateOne({ _id: eventDoc._id }, { $set: { status: 'pending', lastError: (err as Error).message }, $inc: { attempts: 1 } });
    if ((eventDoc as { attempts?: number }).attempts && (eventDoc as { attempts?: number }).attempts! > 10) {
      await InboundEventModel.updateOne({ _id: eventDoc._id }, { $set: { status: 'dead' } });
    }
  } finally { session.endSession(); }
}

export function startStripeProcessor() {
  setInterval(async () => {
    const pending = await InboundEventModel.find({ source: 'stripe', status: 'pending' }).limit(20).lean();
    for (const ev of pending) await processOne(ev as any);
  }, 1000);
}

