import type { Socket } from 'socket.io';

export function withCleanup(socket: Socket) {
  const cleanups: Array<() => void> = [];
  socket.on('disconnect', () => { for (const c of cleanups) { try { c(); } catch {} } cleanups.length = 0; });
  return {
    track: (cleanup: () => void) => cleanups.push(cleanup),
    subscribe: <T>(emitter: { on: (e: string, l: (v: T) => void) => void; off: (e: string, l: (v: T) => void) => void }, event: string, listener: (v: T) => void) => {
      emitter.on(event, listener);
      cleanups.push(() => emitter.off(event, listener));
    }
  };
}

