import { Server, Socket } from 'socket.io';
import { domainEventBus } from '../events/domain.bus';
import { withCleanup } from './lifecycle';

export function attachOrderNamespace(io: Server) {
  const ns = io.of('/orders');
  ns.on('connection', (socket: Socket) => {
    const lc = withCleanup(socket);
    socket.on('order:watch', async (orderId: string) => {
      await socket.join(`order:${orderId}`);
      lc.track(() => { socket.leave(`order:${orderId}`); });
    });
    socket.on('order:unwatch', (orderId: string) => socket.leave(`order:${orderId}`));
  });
  domainEventBus.on('OrderStatusChanged', (evt: { orderId: string; status: string }) => {
    ns.to(`order:${evt.orderId}`).emit('order:update', evt);
  });
}

