import { Request, Response, NextFunction } from 'express';
import { redis } from '../infra/redis';
import { HttpError } from '../errors/http-error';
import crypto from 'node:crypto';

const LUA = `
local key = KEYS[1]
local now = tonumber(ARGV[1])
local windowMs = tonumber(ARGV[2])
local limit = tonumber(ARGV[3])
local member = ARGV[4]
redis.call('ZREMRANGEBYSCORE', key, 0, now - windowMs)
local count = redis.call('ZCARD', key)
if count >= limit then return 0 end
redis.call('ZADD', key, now, member)
redis.call('PEXPIRE', key, windowMs)
return 1
`;

export function slidingWindow(opts: { keyFor: (req: Request) => string | null; windowMs: number; limit: number; reason: string }) {
  return async (req: Request, _res: Response, next: NextFunction) => {
    const key = opts.keyFor(req);
    if (!key) return next();
    const now = Date.now();
    const member = `${now}-${crypto.randomBytes(4).toString('hex')}`;
    const allowed = await redis.eval(LUA, { keys: [key], arguments: [String(now), String(opts.windowMs), String(opts.limit), member] });
    if (allowed !== 1) return next(new HttpError(429, opts.reason));
    next();
  };
}

import { Request, Response, NextFunction } from 'express';
import { redis } from '../infra/redis';
import { HttpError } from '../errors/http-error';
import { auditLog } from '../services/audit.service';

const LOCKOUT_THRESHOLD = 5;
const LOCKOUT_WINDOW_MS = 5 * 60 * 1000;
const LOCKOUT_DURATION_MS = 15 * 60 * 1000;

export async function checkAccountLock(req: Request, _res: Response, next: NextFunction) {
  const email = (req.body?.email as string | undefined)?.toLowerCase();
  if (!email) return next();
  const lockKey = `acct:lock:${email}`;
  const locked = await redis.get(lockKey);
  if (locked) return next(new HttpError(423, 'ACCOUNT_LOCKED'));
  next();
}

export async function recordAuthFailure(email: string, ip: string) {
  const failKey = `acct:fail:${email.toLowerCase()}`;
  const lockKey = `acct:lock:${email.toLowerCase()}`;
  const count = await redis.incr(failKey);
  if (count === 1) await redis.pexpire(failKey, LOCKOUT_WINDOW_MS);
  if (count >= LOCKOUT_THRESHOLD) {
    await redis.set(lockKey, '1', { PX: LOCKOUT_DURATION_MS });
    await auditLog({ action: 'account.locked', email, ip, reason: `${count} failures` });
  }
}

export async function recordAuthSuccess(email: string) {
  await redis.del(`acct:fail:${email.toLowerCase()}`);
}

