import { ReactNode, useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { AuthStateContext, type AuthState, type User } from './AuthStateContext';
import { AuthActionsContext, type AuthActions } from './AuthActionsContext';
import { api, clearApiCache } from '../api/client';

const SS_KEY = 'auth.user';

function loadOptimistic(): User | null {
  try { const raw = sessionStorage.getItem(SS_KEY); return raw ? (JSON.parse(raw) as User) : null; } catch { return null; }
}

export function AuthProvider({ children }: { children: ReactNode }) {
  const initial = loadOptimistic();
  const [state, setState] = useState<AuthState>(initial ? { user: initial, status: 'authenticated' } : { user: null, status: 'loading' });
  const mountedRef = useRef(true);

  useEffect(() => () => { mountedRef.current = false; }, []);

  useEffect(() => {
    (async () => {
      try {
        const me = await api.get<User>('/me');
        if (!mountedRef.current) return;
        sessionStorage.setItem(SS_KEY, JSON.stringify(me));
        setState({ user: me, status: 'authenticated' });
      } catch {
        if (!mountedRef.current) return;
        sessionStorage.removeItem(SS_KEY);
        setState({ user: null, status: 'guest' });
      }
    })();
  }, []);

  useEffect(() => {
    const onStorage = (e: StorageEvent) => {
      if (e.key === SS_KEY && e.newValue === null) {
        clearApiCache();
        setState({ user: null, status: 'guest' });
      }
    };
    window.addEventListener('storage', onStorage);
    return () => window.removeEventListener('storage', onStorage);
  }, []);

  const login = useCallback(async (email: string, password: string) => {
    const r = await api.post<{ user: User }>('/auth/login', { email, password });
    sessionStorage.setItem(SS_KEY, JSON.stringify(r.user));
    setState({ user: r.user, status: 'authenticated' });
  }, []);

  const logout = useCallback(() => {
    api.post('/auth/logout', {}).catch(() => {});
    sessionStorage.removeItem(SS_KEY);
    clearApiCache();
    setState({ user: null, status: 'guest' });
  }, []);

  const actions = useMemo<AuthActions>(() => ({ login, logout }), [login, logout]);

  return (
    <AuthStateContext.Provider value={state}>
      <AuthActionsContext.Provider value={actions}>{children}</AuthActionsContext.Provider>
    </AuthStateContext.Provider>
  );
}

const cache = new Map<string, unknown>();

export function clearApiCache() { cache.clear(); }

export const api = {
  async get<T>(path: string): Promise<T> {
    if (cache.has(path)) return cache.get(path) as T;
    const res = await fetch(`/api${path}`, { credentials: 'include' });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const data = await res.json() as T;
    cache.set(path, data);
    return data;
  },
  async post<T>(path: string, body: unknown): Promise<T> {
    const res = await fetch(`/api${path}`, { method: 'POST', credentials: 'include', headers: { 'content-type': 'application/json' }, body: JSON.stringify(body) });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    return res.json();
  }
};

