import { Server, Socket } from 'socket.io';
import { redis } from '../infra/redis';
import { OpportunityModel } from '../models/opportunity.model';

interface AuthedSocket extends Socket { data: { userId: string; displayName: string; locks: Set<string> } }

const LOCK_TTL_SECONDS = 10;

export function attachOpportunityNamespace(io: Server) {
  const ns = io.of('/opportunities');
  ns.on('connection', (socket: AuthedSocket) => {
    socket.data.locks = new Set();
    socket.on('opp:join', async (oppId: string) => {
      await socket.join(`opp:${oppId}`);
      const lockPattern = `lock:opp:${oppId}:*`;
      const keys = await redis.keys(lockPattern);
      const locks: Record<string, { userId: string }> = {};
      for (const k of keys) {
        const userId = await redis.get(k);
        if (userId) locks[k.split(':').pop()!] = { userId };
      }
      socket.emit('opp:locks', locks);
    });
    socket.on('field:lock', async (oppId: string, field: string, ack: (ok: boolean) => void) => {
      const key = `lock:opp:${oppId}:${field}`;
      const set = await redis.set(key, socket.data.userId, { EX: LOCK_TTL_SECONDS, NX: true });
      if (set === 'OK') {
        socket.data.locks.add(key);
        ns.to(`opp:${oppId}`).emit('field:locked', { field, userId: socket.data.userId, displayName: socket.data.displayName });
        ack(true);
      } else { ack(false); }
    });
    socket.on('field:heartbeat', async (oppId: string, field: string) => {
      const key = `lock:opp:${oppId}:${field}`;
      const owner = await redis.get(key);
      if (owner === socket.data.userId) await redis.expire(key, LOCK_TTL_SECONDS);
    });
    socket.on('field:unlock', async (oppId: string, field: string) => {
      const key = `lock:opp:${oppId}:${field}`;
      const owner = await redis.get(key);
      if (owner === socket.data.userId) {
        await redis.del(key);
        socket.data.locks.delete(key);
        ns.to(`opp:${oppId}`).emit('field:unlocked', { field });
      }
    });
    socket.on('field:change', async (oppId: string, field: string, value: unknown) => {
      const key = `lock:opp:${oppId}:${field}`;
      const owner = await redis.get(key);
      if (owner !== socket.data.userId) return;
      socket.to(`opp:${oppId}`).emit('field:value', { field, value, userId: socket.data.userId });
      await OpportunityModel.updateOne({ _id: oppId }, { $set: { [field]: value } });
    });
    socket.on('disconnect', async () => {
      for (const key of socket.data.locks) {
        const owner = await redis.get(key);
        if (owner === socket.data.userId) {
          await redis.del(key);
          const parts = key.split(':');
          const oppId = parts[2]; const field = parts[3];
          ns.to(`opp:${oppId}`).emit('field:unlocked', { field });
        }
      }
    });
  });
}

import { useEffect, useRef, useState } from 'react';
import { io, Socket } from 'socket.io-client';

type LockState = Record<string, { userId: string; displayName?: string } | null>;
type FieldValues = Record<string, unknown>;

export function useOpportunityCollab(oppId: string, token: string, currentUserId: string, initialValues: FieldValues) {
  const [values, setValues] = useState<FieldValues>(initialValues);
  const [locks, setLocks] = useState<LockState>({});
  const socketRef = useRef<Socket | null>(null);
  const heartbeats = useRef<Map<string, ReturnType<typeof setInterval>>>(new Map());

  useEffect(() => {
    const socket = io('/opportunities', { auth: { token }, transports: ['websocket'] });
    socketRef.current = socket;
    socket.emit('opp:join', oppId);
    socket.on('opp:locks', (l: LockState) => setLocks(l));
    socket.on('field:locked', ({ field, userId, displayName }: { field: string; userId: string; displayName: string }) => setLocks(prev => ({ ...prev, [field]: { userId, displayName } })));
    socket.on('field:unlocked', ({ field }: { field: string }) => setLocks(prev => ({ ...prev, [field]: null })));
    socket.on('field:value', ({ field, value }: { field: string; value: unknown }) => setValues(prev => ({ ...prev, [field]: value })));
    return () => { for (const t of heartbeats.current.values()) clearInterval(t); heartbeats.current.clear(); socket.removeAllListeners(); socket.disconnect(); };
  }, [oppId, token]);

  const acquireLock = (field: string) => new Promise<boolean>(resolve => {
    socketRef.current?.emit('field:lock', oppId, field, (ok: boolean) => {
      if (ok) {
        const t = setInterval(() => socketRef.current?.emit('field:heartbeat', oppId, field), 4000);
        heartbeats.current.set(field, t);
      }
      resolve(ok);
    });
  });
  const releaseLock = (field: string) => {
    const t = heartbeats.current.get(field);
    if (t) { clearInterval(t); heartbeats.current.delete(field); }
    socketRef.current?.emit('field:unlock', oppId, field);
  };
  const writeField = (field: string, value: unknown) => {
    setValues(prev => ({ ...prev, [field]: value }));
    socketRef.current?.emit('field:change', oppId, field, value);
  };
  const canEdit = (field: string) => !locks[field] || locks[field]?.userId === currentUserId;
  return { values, locks, acquireLock, releaseLock, writeField, canEdit };
}

import { useOpportunityCollab } from './useOpportunityCollab';

export function CollabField({ collab, field, label }: { collab: ReturnType<typeof useOpportunityCollab>; field: string; label: string }) {
  const lockedBy = collab.locks[field];
  const isLockedByOther = lockedBy && !collab.canEdit(field);
  return (
    <label className="block">
      <span className="text-sm font-medium">{label}</span>
      {isLockedByOther && <span className="text-xs ml-2 text-amber-600">Editing: {lockedBy?.displayName}</span>}
      <input
        className={`border rounded p-2 w-full ${isLockedByOther ? 'bg-gray-50 cursor-not-allowed' : ''}`}
        value={String(collab.values[field] ?? '')}
        disabled={!!isLockedByOther}
        onFocus={async () => { const ok = await collab.acquireLock(field); if (!ok) console.warn('lock denied'); }}
        onBlur={() => collab.releaseLock(field)}
        onChange={e => collab.writeField(field, e.target.value)}
      />
    </label>
  );
}

