import { OrderModel } from '../models/order.model';
import { PipelineCounterModel } from '../models/pipeline-counter.model';
import { TransitionModel } from '../models/transition.model';
import type { Server } from 'socket.io';

let dirty = false;

export function startPipelineProjector(io: Server) {
  const stream = OrderModel.watch([], { fullDocument: 'updateLookup' });
  stream.on('change', async (event: any) => {
    if (event.operationType === 'insert') {
      const status = event.fullDocument?.status ?? 'pending';
      await PipelineCounterModel.updateOne({ _id: 'singleton' }, { $inc: { [`counts.${status}`]: 1 } }, { upsert: true });
      dirty = true;
    }
    if (event.operationType === 'update' && event.updateDescription?.updatedFields?.status) {
      const newStatus = event.updateDescription.updatedFields.status;
      const oldStatus = event.fullDocumentBeforeChange?.status;
      if (oldStatus && oldStatus !== newStatus) {
        await PipelineCounterModel.updateOne({ _id: 'singleton' }, { $inc: { [`counts.${oldStatus}`]: -1, [`counts.${newStatus}`]: 1 } });
        await TransitionModel.create({ from: oldStatus, to: newStatus, at: new Date() });
        dirty = true;
      }
    }
  });
  setInterval(async () => {
    if (!dirty) return; dirty = false;
    const doc = await PipelineCounterModel.findById('singleton').lean();
    const recent = await TransitionModel.find({ at: { $gt: new Date(Date.now() - 60_000) } }).sort({ at: 1 }).lean();
    io.of('/ops').emit('pipeline:update', { counts: doc?.counts ?? {}, transitions: recent });
  }, 1000);
}

