import { useMemo } from 'react';
import * as THREE from 'three';

export function Stages({ stages, counts }: { stages: ReadonlyArray<string>; counts: Record<string, number> }) {
  const items = useMemo(() => {
    const total = Math.max(1, Object.values(counts).reduce((a, b) => a + b, 0));
    return stages.map((s, i) => ({ name: s, x: (i - (stages.length - 1) / 2) * 5, height: Math.max(0.3, (counts[s] ?? 0) / total * 20) }));
  }, [stages, counts]);
  return (
    <group>
      {items.map(it => (
        <group key={it.name} position={[it.x, it.height / 2, 0]}>
          <mesh>
            <boxGeometry args={[3, it.height, 3]} />
            <meshStandardMaterial color={`hsl(${(stages.indexOf(it.name) * 60) % 360} 70% 55%)`} />
          </mesh>
        </group>
      ))}
    </group>
  );
}

import { useEffect, useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';

type Transition = { from: string; to: string; at: string };

export function Flows({ stages, transitions }: { stages: ReadonlyArray<string>; transitions: Transition[] }) {
  const groupRef = useRef<THREE.Group>(null);
  const particles = useRef<{ from: number; to: number; t: number; mesh: THREE.Mesh }[]>([]);

  useEffect(() => {
    const now = Date.now();
    for (const tr of transitions) {
      const age = now - new Date(tr.at).getTime();
      if (age > 60_000) continue;
      if (particles.current.find(p => Math.abs(p.t - age / 60_000) < 0.01)) continue;
      const fromIdx = stages.indexOf(tr.from);
      const toIdx = stages.indexOf(tr.to);
      if (fromIdx < 0 || toIdx < 0) continue;
      const geom = new THREE.SphereGeometry(0.2, 8, 8);
      const mat = new THREE.MeshStandardMaterial({ color: 'white', emissive: 'white', emissiveIntensity: 0.7 });
      const mesh = new THREE.Mesh(geom, mat);
      groupRef.current?.add(mesh);
      particles.current.push({ from: fromIdx, to: toIdx, t: age / 60_000, mesh });
    }
  }, [transitions, stages]);

  useFrame((_state, delta) => {
    const next: typeof particles.current = [];
    for (const p of particles.current) {
      p.t += delta * 0.5;
      if (p.t >= 1) {
        groupRef.current?.remove(p.mesh);
        p.mesh.geometry.dispose();
        (p.mesh.material as THREE.Material).dispose();
        continue;
      }
      const fromX = (p.from - (stages.length - 1) / 2) * 5;
      const toX = (p.to - (stages.length - 1) / 2) * 5;
      p.mesh.position.set(fromX + (toX - fromX) * p.t, 6 + Math.sin(p.t * Math.PI) * 3, 0);
      next.push(p);
    }
    particles.current = next;
  });

  useEffect(() => () => {
    for (const p of particles.current) { p.mesh.geometry.dispose(); (p.mesh.material as THREE.Material).dispose(); }
  }, []);

  return <group ref={groupRef} />;
}

import { useEffect, useState } from 'react';
import { io } from 'socket.io-client';

type Update = { counts: Record<string, number>; transitions: { from: string; to: string; at: string }[] };

export function usePipelineLive(token: string) {
  const [counts, setCounts] = useState<Record<string, number>>({});
  const [transitions, setTransitions] = useState<Update['transitions']>([]);
  useEffect(() => {
    const socket = io('/ops', { auth: { token }, transports: ['websocket'] });
    socket.on('pipeline:update', (u: Update) => { setCounts(u.counts); setTransitions(u.transitions); });
    return () => { socket.removeAllListeners(); socket.disconnect(); };
  }, [token]);
  return { counts, transitions };
}

