declare global { namespace Express { interface Request { user?: { id: string; role: string } } } }

export function requireAuth(req: Request, _res: Response, next: NextFunction) {
  try {
    const auth = req.headers.authorization;
    if (!auth?.startsWith('Bearer ')) throw new HttpError(401, 'UNAUTHENTICATED');
    const payload = jwt.verify(auth.slice(7), process.env.JWT_SECRET!) as { sub: string; role: string };
