  } catch { next(new HttpError(401, 'UNAUTHENTICATED')); }
}

import { Schema, model } from 'mongoose';

const ApiKeySchema = new Schema({
  orgId: { type: Schema.Types.ObjectId, required: true, ref: 'Org', index: true },
  prefix: { type: String, required: true, index: true },
  hash: { type: String, required: true },
  scopes: { type: [String], required: true },
  name: { type: String, required: true },
  createdBy: { type: Schema.Types.ObjectId, ref: 'User', required: true },
  status: { type: String, enum: ['active','deprecated','revoked'], default: 'active', index: true },
  expiresAt: Date,
  lastUsedAt: Date
}, { timestamps: true });

export const ApiKeyModel = model('ApiKey', ApiKeySchema);

import bcrypt from 'bcrypt';
import crypto from 'node:crypto';
import { ApiKeyModel } from '../models/api-key.model';
import { Types } from 'mongoose';

export const apiKeyService = {
  async issue(opts: { orgId: Types.ObjectId; createdBy: Types.ObjectId; name: string; scopes: string[]; expiresAt?: Date }) {
    const secret = crypto.randomBytes(32).toString('base64url');
    const fullKey = `sk_live_${secret}`;
    const prefix = fullKey.slice(0, 12);
    const hash = await bcrypt.hash(fullKey, 12);
    const doc = await ApiKeyModel.create({ ...opts, prefix, hash, status: 'active' });
    return { id: doc._id, key: fullKey, prefix };
  },
  async verify(presented: string) {
    if (!presented.startsWith('sk_live_')) return null;
    const prefix = presented.slice(0, 12);
    const candidates = await ApiKeyModel.find({ prefix, status: { $in: ['active','deprecated'] } });
    for (const c of candidates) {
      if (c.expiresAt && c.expiresAt.getTime() < Date.now()) continue;
      const match = await bcrypt.compare(presented, c.hash);
      if (match) {
        ApiKeyModel.updateOne({ _id: c._id }, { $set: { lastUsedAt: new Date() } }).catch(() => {});
        return c;
      }
    }
    return null;
  },
  async revoke(id: Types.ObjectId) {
    await ApiKeyModel.updateOne({ _id: id }, { $set: { status: 'revoked' } });
  }
};

import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';
import { HttpError } from '../errors/http-error';
import { apiKeyService } from '../services/api-key.service';
import { auditLog } from '../services/audit.service';

declare global { namespace Express { interface Request { user?: { id: string; role: string }; apiKey?: { id: string; orgId: string; scopes: string[] } } } }

export async function requireAuth(req: Request, _res: Response, next: NextFunction) {
  try {
    const auth = req.headers.authorization;
    if (!auth?.startsWith('Bearer ')) throw new HttpError(401, 'UNAUTHENTICATED');
    const token = auth.slice(7);
    if (token.startsWith('sk_live_')) {
      const key = await apiKeyService.verify(token);
      if (!key) throw new HttpError(401, 'UNAUTHENTICATED');
      req.apiKey = { id: key._id.toString(), orgId: key.orgId.toString(), scopes: key.scopes };
      auditLog({ action: 'apikey.used', keyId: req.apiKey.id, orgId: req.apiKey.orgId, path: req.path }).catch(() => {});
      return next();
    }
    const payload = jwt.verify(token, process.env.JWT_SECRET!) as { sub: string; role: string };
    req.user = { id: payload.sub, role: payload.role };
    next();
  } catch { next(new HttpError(401, 'UNAUTHENTICATED')); }
}

export function requireScope(scope: string) {
  return (req: Request, _res: Response, next: NextFunction) => {
    if (req.user) return next(); // user JWTs use role-based access elsewhere
    if (req.apiKey?.scopes.includes(scope) || req.apiKey?.scopes.includes('*')) return next();
    next(new HttpError(403, 'INSUFFICIENT_SCOPE'));
  };
}

