import { Request, Response, NextFunction } from 'express';
import { S3Client, PutObjectCommand } from '@aws-sdk/client-s3';
import { getSignedUrl } from '@aws-sdk/s3-request-presigner';
import crypto from 'node:crypto';
import { FileModel } from '../models/file.model';
import { enqueueScan } from '../workers/scan-queue';
import { HttpError } from '../errors/http-error';

const s3 = new S3Client({ region: process.env.AWS_REGION! });
const BUCKET = process.env.S3_BUCKET!;

export const initUpload = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { filename, contentType, size } = req.body as { filename: string; contentType: string; size: number };
    if (size > 500 * 1024 * 1024) throw new HttpError(413, 'FILE_TOO_LARGE');
    const fileId = crypto.randomUUID();
    const key = `uploads/${fileId}/${filename}`;
    const uploadUrl = await getSignedUrl(s3, new PutObjectCommand({ Bucket: BUCKET, Key: key, ContentType: contentType }), { expiresIn: 600 });
    await FileModel.create({ _id: fileId, userId: req.user!.id, key, filename, contentType, size, status: 'pending_upload' });
    res.json({ fileId, uploadUrl, finalUrl: `/api/files/${fileId}` });
  } catch (err) { next(err); }
};

export const completeUpload = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { fileId } = req.params;
    const file = await FileModel.findOneAndUpdate({ _id: fileId, userId: req.user!.id, status: 'pending_upload' }, { $set: { status: 'pending_scan' } }, { new: true });
    if (!file) throw new HttpError(404, 'NOT_FOUND_OR_INVALID');
    await enqueueScan(fileId);
    res.json({ fileId, status: file.status });
  } catch (err) { next(err); }
};

export const getFile = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const file = await FileModel.findById(req.params.fileId);
    if (!file) throw new HttpError(404, 'NOT_FOUND');
    if (file.status !== 'clean') throw new HttpError(409, `NOT_READY:${file.status}`);
    const { GetObjectCommand } = await import('@aws-sdk/client-s3');
    const url = await getSignedUrl(s3, new GetObjectCommand({ Bucket: BUCKET, Key: file.key }), { expiresIn: 600 });
    res.redirect(url);
  } catch (err) { next(err); }
};

import { FileModel } from '../models/file.model';
import { S3Client, GetObjectCommand, DeleteObjectCommand } from '@aws-sdk/client-s3';
import { io } from '../infra/socketio';
import { spawn } from 'node:child_process';
import fs from 'node:fs';
import path from 'node:path';
import { Readable } from 'node:stream';

const s3 = new S3Client({ region: process.env.AWS_REGION! });
const BUCKET = process.env.S3_BUCKET!;

async function scanFile(fileId: string) {
  const file = await FileModel.findById(fileId);
  if (!file || file.status !== 'pending_scan') return;
  const tmp = path.join('/tmp', fileId);
  const obj = await s3.send(new GetObjectCommand({ Bucket: BUCKET, Key: file.key }));
  await new Promise<void>((resolve, reject) => {
    const stream = obj.Body as Readable;
    const out = fs.createWriteStream(tmp);
    stream.pipe(out).on('finish', resolve).on('error', reject);
  });
  const result = await new Promise<'clean'|'infected'|'error'>((resolve) => {
    const proc = spawn('clamdscan', ['--no-summary', tmp]);
    proc.on('exit', code => { resolve(code === 0 ? 'clean' : code === 1 ? 'infected' : 'error'); });
  });
  fs.unlinkSync(tmp);
  if (result === 'infected') await s3.send(new DeleteObjectCommand({ Bucket: BUCKET, Key: file.key }));
  await FileModel.updateOne({ _id: fileId }, { $set: { status: result === 'error' ? 'pending_scan' : result, scannedAt: new Date() } });
  io.of('/files').to(`user:${file.userId}`).emit('file:status', { fileId, status: result });
}

export function startScanWorker(queueGet: () => Promise<string | null>) {
  setInterval(async () => {
    const fileId = await queueGet();
    if (fileId) scanFile(fileId).catch(err => console.error('scan failed', fileId, err));
  }, 500);
}

import { useState } from 'react';
import { io } from 'socket.io-client';

export function Uploader({ token }: { token: string }) {
  const [progress, setProgress] = useState(0);
  const [status, setStatus] = useState<'idle'|'uploading'|'scanning'|'clean'|'infected'|'error'>('idle');
  const [finalUrl, setFinalUrl] = useState<string | null>(null);

  const handleFile = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]; if (!file) return;
    setStatus('uploading'); setProgress(0); setFinalUrl(null);
    const init = await fetch('/api/upload/init', { method: 'POST', credentials: 'include', headers: { 'content-type': 'application/json' }, body: JSON.stringify({ filename: file.name, contentType: file.type, size: file.size }) }).then(r => r.json());
    await new Promise<void>((resolve, reject) => {
      const xhr = new XMLHttpRequest();
      xhr.open('PUT', init.uploadUrl);
      xhr.setRequestHeader('content-type', file.type);
      xhr.upload.onprogress = ev => setProgress(ev.loaded / ev.total * 100);
      xhr.onload = () => xhr.status < 300 ? resolve() : reject(new Error(`upload failed ${xhr.status}`));
      xhr.onerror = () => reject(new Error('upload network error'));
      xhr.send(file);
    });
    await fetch(`/api/upload/${init.fileId}/complete`, { method: 'POST', credentials: 'include' });
    setStatus('scanning');
    const socket = io('/files', { auth: { token }, transports: ['websocket'] });
    socket.on('file:status', (m: { fileId: string; status: 'clean'|'infected'|'error' }) => {
      if (m.fileId !== init.fileId) return;
      setStatus(m.status);
      if (m.status === 'clean') setFinalUrl(init.finalUrl);
      socket.disconnect();
    });
  };

  return (
    <div>
      <input type="file" onChange={handleFile} />
      {status === 'uploading' && <progress value={progress} max={100} />}
      {status === 'scanning' && <div>Scanning for viruses...</div>}
      {status === 'clean' && finalUrl && <a href={finalUrl}>Download</a>}
      {status === 'infected' && <div className="text-red-600">File was infected and has been removed.</div>}
    </div>
  );
}
